using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Shared state ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
var notebook = new Notebook();
var webSearch = new WebSearchTool(httpClient);

// --- Build the chat client ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create the research agent ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(webSearch.FetchPage),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic using the
    tools available to you and produce a well-organized summary.

    Workflow:
    1. Break the topic into 2-3 key questions.
    2. Use search_web to find relevant information for each question.
    3. Optionally use fetch_page to read specific pages for deeper detail.
    4. Use save_note to record important findings as you go — include the source URL.
    5. After gathering enough information, use get_notes to review everything you collected.
    6. Produce a final summary with sections, key facts, and source references.

    Be thorough but concise. Always cite your sources.
    """;

ChatClientAgent agent = chatClient.AsAIAgent(
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Interactive loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔬 Research Agent Ready        ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.          ║");
Console.WriteLine("║  Type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic: ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic))
        continue;
    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"\nResearching \"{topic}\"...\n");
    Console.ResetColor();

    try
    {
        using var session = await agent.CreateSessionAsync();
        var response = await agent.RunAsync(
            $"Please research the following topic and provide a comprehensive summary: {topic}",
            session,
            new ChatClientAgentRunOptions(new ChatOptions
            {
                Temperature = 0f,
                MaxOutputTokens = 4096,
            }));

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("\n═══ Research Summary ═══\n");
        Console.ResetColor();

        // Display the final assistant response
        foreach (var message in response.Messages)
        {
            if (message.Role == ChatRole.Assistant && message.Text is { Length: > 0 })
            {
                Console.WriteLine(message.Text);
            }
        }

        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");

// ──────────────────────────────────────────────────────────
// Tool: Web Search
// ──────────────────────────────────────────────────────────

sealed class WebSearchTool(HttpClient httpClient)
{
    [Description("Search the web for information on a topic. Returns results with titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query,
        [Description("Max results to return (1-5)")] int maxResults = 3)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            maxResults = Math.Clamp(maxResults, 1, 5);
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await httpClient.GetStringAsync(url);

            var results = ParseResults(html, maxResults);
            if (results.Count == 0)
                return "No search results found. Try a different query.";

            return string.Join("\n\n", results.Select((r, i) =>
                $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Snippet}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Useful for reading full articles.")]
    public async Task<string> FetchPage(
        [Description("The URL of the page to fetch")] string url)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📄 Fetching: {url}");
        Console.ResetColor();

        try
        {
            var html = await httpClient.GetStringAsync(url);
            var text = StripHtml(html);

            // Limit to ~4000 chars to avoid overwhelming the context
            if (text.Length > 4000)
                text = text[..4000] + "\n\n[Content truncated...]";

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract meaningful text from the page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseResults(string html, int max)
    {
        var results = new List<SearchResult>();

        // Parse DuckDuckGo HTML search result entries
        var resultPattern = ResultRegex();
        var matches = resultPattern.Matches(html);

        foreach (Match match in matches)
        {
            if (results.Count >= max)
                break;

            var resultUrl = WebUtility.HtmlDecode(match.Groups["url"].Value).Trim();
            var title = StripHtml(WebUtility.HtmlDecode(match.Groups["title"].Value)).Trim();
            var snippet = StripHtml(WebUtility.HtmlDecode(match.Groups["snippet"].Value)).Trim();

            if (!string.IsNullOrEmpty(title) && !string.IsNullOrEmpty(resultUrl))
            {
                // DuckDuckGo wraps URLs through a redirect — extract the actual URL
                var actualUrl = ExtractActualUrl(resultUrl);
                results.Add(new SearchResult(title, actualUrl, snippet));
            }
        }

        return results;
    }

    private static string ExtractActualUrl(string ddgUrl)
    {
        // DuckDuckGo redirect format: //duckduckgo.com/l/?uddg=<encoded_url>&...
        var uddgMatch = Regex.Match(ddgUrl, @"uddg=([^&]+)");
        if (uddgMatch.Success)
            return Uri.UnescapeDataString(uddgMatch.Groups[1].Value);

        return ddgUrl.StartsWith("//") ? "https:" + ddgUrl : ddgUrl;
    }

    private static string StripHtml(string html)
    {
        // Remove script/style blocks, then tags, then normalize whitespace
        var text = Regex.Replace(html, @"<(script|style)[^>]*>[\s\S]*?</\1>", " ", RegexOptions.IgnoreCase);
        text = Regex.Replace(text, @"<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"\s+", " ");
        return text.Trim();
    }

    [GeneratedRegex(
        @"<a[^>]+class=""result__a""[^>]+href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ResultRegex();
}

record SearchResult(string Title, string Url, string Snippet);

// ──────────────────────────────────────────────────────────
// Tool: Notebook
// ──────────────────────────────────────────────────────────

sealed class Notebook
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note. Use this to record important findings, facts, or quotes along with the source URL.")]
    public string SaveNote(
        [Description("The content of the note")] string content,
        [Description("The source URL where this information was found")] string source)
    {
        _notes.Add(new Note(content, source));

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes. Returns all notes with their content and source URLs.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");
        Console.ResetColor();

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"Note #{i + 1}:\n  Content: {n.Content}\n  Source: {n.Source}"));
    }

    public void Clear() => _notes.Clear();
}

record Note(string Content, string Source);

